using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

// --- ML.NET setup ---
var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" string → boolean Label column
var pipeline = mlContext.Transforms.CustomMapping<CustomerData, LabelMapping>(
        (input, output) => output.Label = input.Churned == "Yes",
        contractName: null)
    .Append(mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.FastTree(
        labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(dataView);

var predictionEngine = mlContext.Model
    .CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

// --- Endpoints ---
app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (CustomerRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region ?? "East",
        PurchaseHistory = req.PurchaseHistory
    };

    var result = predictionEngine.Predict(input);

    return Results.Ok(new
    {
        Churned = result.PredictedLabel ? "Yes" : "No",
        Probability = Math.Round(result.Probability, 4)
    });
});

app.Run();

// --- Models ---
public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = "";
}

public class LabelMapping
{
    public bool Label { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
}

public record CustomerRequest(float Age, float Income, string? Region, float PurchaseHistory);

